/* BTLoading — multi-type loading indicator atom (Figma 3227:400). */

/* ── Lottie container (spinner / pulse / logo) ──────────────────────── */
.bt-loading--lottie {
  display: block;
  flex-shrink: 0;
}

/* Spinner & pulse — theme-aware Lottie; CSS toggles light/dark via [data-mode="dark"] */
.bt-loading--lottie-themed {
  position: relative;
  flex-shrink: 0;
}

.bt-loading--lottie-themed .bt-loading--lottie {
  position: absolute;
  inset: 0;
}

.bt-loading--lottie--dark {
  display: none;
}

[data-mode="dark"] .bt-loading--lottie--light {
  display: none;
}

[data-mode="dark"] .bt-loading--lottie--dark {
  display: block;
}

/* ── Skeleton shimmer block (Figma 3227:400 light · 4666:2016 dark) ─── */
/* Base: bg.subtler · Shimmer peak: bg.primary — tokens swap via [data-mode="dark"] */
.bt-loading--skeleton {
  background: var(--bg-subtler);
  border-radius: var(--radius-md);
  overflow: hidden;
  position: relative;
}

/* Sweep gradient overlay — animates from left to right */
.bt-loading--skeleton::after {
  content: "";
  position: absolute;
  inset: 0;
  background: linear-gradient(
    90deg,
    transparent 0%,
    var(--bg-primary) 50%,
    transparent 100%
  );
  transform: translateX(-100%);
  animation: bt-loading-shimmer 1.5s ease-in-out infinite;
}

@keyframes bt-loading-shimmer {
  to {
    transform: translateX(200%);
  }
}

/* ── Progress bar ────────────────────────────────────────────────────── */
.bt-loading--progressbar {
  position: relative;
  width: 100%;
  height: 4px;
  background: color-mix(
    in srgb,
    var(--bt-loading-color, var(--color-brand-primary)) 10%,
    transparent
  );
  border-radius: var(--radius-rd);
  overflow: hidden;
}

.bt-loading__progressbar-bar {
  position: absolute;
  top: 0;
  inset-inline-start: 0;
  height: 100%;
  border-radius: var(--radius-rd);
  background: var(--bt-loading-color, var(--color-brand-primary));
  transition: width 300ms ease;
}

/* Indeterminate: bar slides across the track */
.bt-loading__progressbar-bar--indeterminate {
  width: 35%;
  animation: bt-loading-indeterminate 1.4s cubic-bezier(0.4, 0, 0.6, 1) infinite;
}

@keyframes bt-loading-indeterminate {
  0% {
    transform: translateX(-100%);
  }
  100% {
    transform: translateX(386%);
  }
}

@keyframes bt-loading-indeterminate-rtl {
  0% {
    transform: translateX(100%);
  }
  100% {
    transform: translateX(-386%);
  }
}

[dir="rtl"] .bt-loading__progressbar-bar--indeterminate {
  animation-name: bt-loading-indeterminate-rtl;
}

@keyframes bt-loading-shimmer-rtl {
  to {
    transform: translateX(-200%);
  }
}

[dir="rtl"] .bt-loading--skeleton::after {
  transform: translateX(100%);
  animation-name: bt-loading-shimmer-rtl;
}

/**
 * BTLoading — multi-type loading indicator atom.
 * Mirrors @btech/ui-vue BTLoading one-to-one (same props, same logic).
 * Figma: node 3227:400.
 *
 * ## Usage:
 * ```tsx
 * // Default spinner
 * <BTLoading />
 *
 * // Pulse animation
 * <BTLoading type="pulse" />
 *
 * // Skeleton shimmer block
 * <BTLoading type="skeleton" width={200} />
 *
 * // Skeleton with custom height
 * <BTLoading type="skeleton" width={200} height={80} />
 *
 * // Indeterminate progress bar
 * <BTLoading type="progressbar" />
 *
 * // Determinate 60%
 * <BTLoading type="progressbar" value={0.6} />
 *
 * // BTech logo animation
 * <BTLoading type="logo" size={64} />
 * ```
 */
import * as React from "react";
import Lottie from "lottie-react";
import "./BTLoading.css";
import type { BTLoadingProps } from "./BTLoading.types";
import spinnerData from "@btech/assets/anim/load-spin-anim.json";
import spinnerDataDark from "@btech/assets/anim/load-spin-anim-dark.json";
import pulseData from "@btech/assets/anim/load-pulse-anim.json";
import pulseDataDark from "@btech/assets/anim/load-pulse-anim-dark.json";
import logoData from "@btech/assets/anim/load-btech-anim.json";

/** Multi-type loading indicator. See file header for usage. */
export const BTLoading = React.forwardRef<HTMLDivElement, BTLoadingProps>(
  (
    {
      type = "spinner",
      color,
      value,
      size = 48,
      width = "100%",
      height = "40px",
      ...rest
    },
    ref,
  ) => {
    const isLottie = type === "spinner" || type === "pulse" || type === "logo";
    const isThemedLottie = type === "spinner" || type === "pulse";
    const isSkeleton = type === "skeleton";
    const isProgressbar = type === "progressbar";
    const isIndeterminate = isProgressbar && value === undefined;

    // Clamp value to [0, 1] to keep aria-valuenow valid
    const clampedValue =
      value !== undefined ? Math.min(1, Math.max(0, value)) : undefined;

    const themedLottieLight =
      type === "spinner" ? spinnerData :
      type === "pulse"   ? pulseData :
      null;

    const themedLottieDark =
      type === "spinner" ? spinnerDataDark :
      type === "pulse"   ? pulseDataDark :
      null;

    const animationData = type === "logo" ? logoData : null;

    // Lottie: spinner & pulse (theme-aware), logo
    if (isLottie && isThemedLottie && themedLottieLight && themedLottieDark) {
      return (
        <div
          role="status"
          aria-label="Loading"
          className="bt-loading--lottie-themed"
          style={{ width: size, height: size }}
        >
          <Lottie
            animationData={themedLottieLight}
            className="bt-loading--lottie bt-loading--lottie--light"
            style={{ width: size, height: size }}
            loop
            autoplay
          />
          <Lottie
            animationData={themedLottieDark}
            className="bt-loading--lottie bt-loading--lottie--dark"
            style={{ width: size, height: size }}
            loop
            autoplay
          />
        </div>
      );
    }

    if (isLottie && animationData) {
      return (
        <Lottie
          role="status"
          aria-label="Loading"
          animationData={animationData}
          className="bt-loading--lottie"
          style={{ width: size, height: size }}
          loop
          autoplay
        />
      );
    }

    // Skeleton shimmer block
    if (isSkeleton) {
      return (
        <div
          role="status"
          aria-label="Loading"
          {...rest}
          ref={ref}
          className={["bt-loading--skeleton", rest.className]
            .filter(Boolean)
            .join(" ")}
          style={{
            width: typeof width === "number" ? `${width}px` : width,
            height: typeof height === "number" ? `${height}px` : height,
            ...rest.style,
          }}
        />
      );
    }

    // Progress bar
    if (isProgressbar) {
      const colorStyle = color
        ? ({ "--bt-loading-color": color } as React.CSSProperties)
        : undefined;

      return (
        <div
          role="progressbar"
          aria-valuenow={
            clampedValue !== undefined
              ? Math.round(clampedValue * 100)
              : undefined
          }
          aria-valuemin={0}
          aria-valuemax={100}
          {...rest}
          ref={ref}
          className={["bt-loading--progressbar", rest.className]
            .filter(Boolean)
            .join(" ")}
          style={colorStyle ? { ...colorStyle, ...rest.style } : rest.style}
        >
          <div
            className={
              "bt-loading__progressbar-bar" +
              (isIndeterminate
                ? " bt-loading__progressbar-bar--indeterminate"
                : "")
            }
            style={
              !isIndeterminate && clampedValue !== undefined
                ? { width: `${clampedValue * 100}%` }
                : undefined
            }
          />
        </div>
      );
    }

    return null;
  },
);

BTLoading.displayName = "BTLoading";

import type { HTMLAttributes } from 'react';

/**
 * Props for BTLoading.
 *
 * @example
 * <BTLoading />
 * <BTLoading type="pulse" />
 * <BTLoading type="skeleton" width={200} />
 * <BTLoading type="progressbar" value={0.6} color="#e53e3e" />
 * <BTLoading type="logo" size={64} />
 */
export type BTLoadingType = 'spinner' | 'pulse' | 'skeleton' | 'progressbar' | 'logo';

export interface BTLoadingProps extends HTMLAttributes<HTMLDivElement> {
  /**
   * Which indicator to render.
   * @default 'spinner'
   */
  type?: BTLoadingType;
  /**
   * CSS color string applied to progressbar bar + track only.
   * Has no effect on spinner, pulse, skeleton, or logo.
   * @default 'var(--color-brand-primary)'
   */
  color?: string;
  /**
   * Determinate progress for progressbar (0–1).
   * Omit for indeterminate looping animation.
   */
  value?: number;
  /**
   * Width × height in px for spinner / pulse / logo.
   * @default 48
   */
  size?: number;
  /**
   * Width of skeleton block. Accepts px number or CSS string ('200px', '50%').
   * @default '100%'
   */
  width?: number | string;
  /**
   * Height of skeleton block. Accepts px number or CSS string ('80px', '100%').
   * @default '40px'
   */
  height?: number | string;
}
